import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getArtiste } from '../api/artisteService';

export default function ArtisteDetail(){
  const { id } = useParams();
  const [artiste, setArtiste] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(()=>{
    setLoading(true);
    getArtiste(id).then(r=>setArtiste(r.data)).catch(()=>{}).finally(()=>setLoading(false));
  },[id]);

  if(loading) return <div>Chargement...</div>;
  if(!artiste) return <div>Artiste non trouvé</div>;

  return (
    <div>
      <h2>{artiste.nom || artiste.name}</h2>
      <p>ID: {artiste.id}</p>
      <p>Description: {artiste.description || '—'}</p>
      <p>
        <Link to={`/artistes/${id}/edit`}>Modifier</Link>
      </p>
      <p>
        <Link to="/artistes">Retour à la liste</Link>
      </p>
    </div>
  );
}
